import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"faq/troubleshooting.md","filePath":"faq/troubleshooting.md"}'),n={name:"faq/troubleshooting.md"};function r(i,e,c,h,l,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="app-issues" tabindex="-1">App Issues <a class="header-anchor" href="#app-issues" aria-label="Permalink to &quot;App Issues&quot;">​</a></h2><p><strong>The app is showing old data after an update</strong> Hard refresh the app: on Android long-press the app icon → App Info → Clear Cache. On iOS delete and reinstall the PWA.</p><p><strong>Analytics show no data despite having logged games</strong> Check the event type filter — it may be set to a specific event type that has no data. Set it to All to see all data. Also check that the correct team is selected in the team selector.</p><p><strong>The schedule shows no games</strong> Confirm you are viewing the correct team. Games entered through Game Mode appear on the schedule — if games are missing check that they were ended properly with a recorded result.</p><h2 id="voice-logging-issues" tabindex="-1">Voice Logging Issues <a class="header-anchor" href="#voice-logging-issues" aria-label="Permalink to &quot;Voice Logging Issues&quot;">​</a></h2><p><strong>Voice logging cuts off before I finish speaking</strong> On desktop this is a browser timeout. Speak at a natural pace without long pauses. On mobile use the keyboard microphone which does not have a timeout — speak as long as needed then tap the arrow button.</p><p><strong>The wrong player is being matched</strong> The AI matches player names to your roster. Speak the player&#39;s last name clearly. If the player is not being matched select them manually from the dropdown on the confirmation card before saving.</p><p><strong>Voice logging shows subscription required</strong> Voice logging requires a Player, Coach, or Organization subscription. Free accounts do not have voice logging access.</p><h2 id="data-issues" tabindex="-1">Data Issues <a class="header-anchor" href="#data-issues" aria-label="Permalink to &quot;Data Issues&quot;">​</a></h2><p><strong>I cannot delete a record</strong> Records older than 2 hours require a correction reason. Select a reason and type DELETE in the confirmation field. If deletion still fails contact support — there may be a permissions issue.</p><p><strong>ERA is showing a strange value</strong> Check that innings pitched is being recorded correctly in the pitching logger. ERA requires both earned runs and innings pitched to calculate. If innings pitched is zero or null ERA cannot be calculated.</p><h2 id="account-issues" tabindex="-1">Account Issues <a class="header-anchor" href="#account-issues" aria-label="Permalink to &quot;Account Issues&quot;">​</a></h2><p><strong>I cannot log in</strong> Try resetting your password from the login screen. If the issue persists contact support at support@diamondanalytics.app.</p><p><strong>I was invited to a team but cannot see it</strong> Ensure you signed in with the same email address the invite was sent to. If you created a new account check that you used the invite link not the main sign-up page.</p><h2 id="contact-support" tabindex="-1">Contact Support <a class="header-anchor" href="#contact-support" aria-label="Permalink to &quot;Contact Support&quot;">​</a></h2><p>For issues not covered here contact support at <strong>support@diamondanalytics.app</strong>.</p><p>When contacting support please include:</p><ul><li>Your email address</li><li>The team name</li><li>The device and browser you are using</li><li>A description of what you expected to happen and what actually happened</li></ul>',19)])])}const g=t(n,[["render",r]]);export{d as __pageData,g as default};
